import pytest

@pytest.mark.parametrize("age_days,expected_http", [
    (1,  201),
    (59, 201),
    (60, 201),
    (61, 422),
    (90, 422),
])
def test_dispute_decision_table_all_combinations(
    api_client, create_transaction_fixture, age_days, expected_http
):
    txn = create_transaction_fixture(age_days=age_days)
    payload = {
        "transaction_id": txn["id"],
        "reason": "Decision table case"
    }
    resp = api_client.post("/disputes", json=payload)
    assert resp.status_code == expected_http, (
        f"age={age_days}d: expected {expected_http}, got {resp.status_code}"
    )
